 30â†’    var matched = false
 31â†’    collect { value ->
 32â†’        if (matched) {
 33â†’            emit(value)
 34â†’        } else if (!predicate(value)) {
 35â†’            matched = true
 36â†’            emit(value)
 37â†’        }
