 41â†’/**
 42â†’ * Returns a flow that contains first [count] elements.
 43â†’ * When [count] elements are consumed, the original flow is cancelled.
 44â†’ * Throws [IllegalArgumentException] if [count] is not positive.
 45â†’ */
 46â†’public fun <T> Flow<T>.take(count: Int): Flow<T> {
 47â†’    require(count > 0) { "Requested element count $count should be positive" }
 48â†’    return flow {
 49â†’        var consumed = 0
 50â†’        try {
 51â†’            collect { value ->
 52â†’                // Note: this for take is not written via collectWhile on purpose.
 53â†’                // It checks condition first and then makes a tail-call to either emit or emitAbort.
 54â†’                // This way normal execution does not require a state machine, only a termination (emitAbort).
 55â†’                // See "TakeBenchmark" for comparision of different approaches.
 56â†’                if (++consumed < count) {
 57â†’                    return@collect emit(value)
 58â†’                } else {
 59â†’                    return@collect emitAbort(value)
 60â†’                }
 61â†’            }
 62â†’        } catch (e: AbortFlowException) {
 63â†’            e.checkOwnership(owner = this)
 64â†’        }
