111â†’    @BuilderInference transform: suspend FlowCollector<R>.(value: T) -> Boolean
112â†’): Flow<R> =
113â†’    safeFlow { // Note: safe flow is used here, because collector is exposed to transform on each operation
114â†’        // This return is needed to work around a bug in JS BE: KT-39227
115â†’        return@safeFlow collectWhile { value ->
116â†’            transform(value)
117â†’        }
118â†’    }
