121â†’internal suspend inline fun <T> Flow<T>.collectWhile(crossinline predicate: suspend (value: T) -> Boolean) {
122â†’    val collector = object : FlowCollector<T> {
123â†’        override suspend fun emit(value: T) {
124â†’            // Note: we are checking predicate first, then throw. If the predicate does suspend (calls emit, for example)
125â†’            // the the resulting code is never tail-suspending and produces a state-machine
126â†’            if (!predicate(value)) {
127â†’                throw AbortFlowException(this)
128â†’            }
129â†’        }
130â†’    }
131â†’    try {
132â†’        collect(collector)
133â†’    } catch (e: AbortFlowException) {
134â†’        e.checkOwnership(collector)
135â†’    }
